const items = $input.all();

return items.map((item) => {
  const data = item.json.body || item.json || {};

  const report_id =
    'RPT-' + Math.random().toString(36).substring(2, 9).toUpperCase();

  let refs = [];
  const rawRefs = data.reference_artists;
  if (Array.isArray(rawRefs)) {
    refs = rawRefs
      .map((entry) => (typeof entry === 'string' ? entry.trim() : String(entry || '').trim()))
      .filter(Boolean);
  } else if (typeof rawRefs === 'string') {
    refs = rawRefs.split(',').map((entry) => entry.trim()).filter(Boolean);
  }

  const email = (data.contact_email || data.email || '').toString().trim();
  const soundcloudLink = (
    data.soundcloud_link ||
    data.private_soundcloud_link ||
    ''
  )
    .toString()
    .trim();

  const instagramRaw = (data.instagram_handle || data.instagram || '')
    .toString()
    .trim();

  return {
    json: {
      report_id,
      artist_name: data.artist_name ? data.artist_name.toString().trim() : '',
      contact_email: email,
      email,
      genre: data.genre ? data.genre.toString().trim() : 'Electronic',
      soundcloud_link: soundcloudLink,
      reference_artists: refs,
      instagram_handle: instagramRaw,
      instagram: instagramRaw.replace(/^@+/, ''),
      submitted_at: data.submitted_at || null,
      source: data.source || 'labelscout-landing-page',
      timestamp: new Date().toISOString(),
      phase: 'phase-01-normalize',
    },
  };
});
